// Extract error information and campaign ID
const errorData = $input.item.json;

// Get workflow execution data
const workflowId = errorData.workflow?.id;
const workflowName = errorData.workflow?.name;
const executionId = errorData.execution?.id;
const errorNode = errorData.node?.name;
const errorMessage = errorData.error?.message || 'Unknown error';
const errorStack = errorData.error?.stack || '';

// Try to extract campaign ID from various possible locations
let campaignId = null;

// Check if it's in the error trigger data
if (errorData.data?.main?.[0]?.[0]?.json?.campaignId) {
  campaignId = errorData.data.main[0][0].json.campaignId;
}

// Check if Webhook Trigger data is available
if (!campaignId && errorData.data?.main?.[0]) {
  for (const item of errorData.data.main[0]) {
    if (item.json?.campaignId) {
      campaignId = item.json.campaignId;
      break;
    }
  }
}

// Log comprehensive error information
console.error('========================================');
console.error('GLOBAL ERROR HANDLER TRIGGERED');
console.error('========================================');
console.error(`Workflow: ${workflowName} (${workflowId})`);
console.error(`Execution ID: ${executionId}`);
console.error(`Failed Node: ${errorNode}`);
console.error(`Error Message: ${errorMessage}`);
console.error(`Campaign ID: ${campaignId || 'NOT FOUND'}`);
console.error('----------------------------------------');
console.error(`Stack Trace: ${errorStack}`);
console.error('========================================');

return [{
  json: {
    workflowId,
    workflowName,
    executionId,
    errorNode,
    errorMessage,
    errorStack,
    campaignId,
    timestamp: new Date().toISOString(),
    hasCampaignId: !!campaignId
  }
}];

// Log that campaign was marked as FAILED
const campaignId = $('Extract Error Info').item.json.campaignId;
const errorMessage = $('Extract Error Info').item.json.errorMessage;

console.log(`[GLOBAL ERROR HANDLER] Campaign ${campaignId} marked as FAILED`);
console.log(`[GLOBAL ERROR HANDLER] Reason: ${errorMessage}`);

return [$json];

// DB update failed - log for manual intervention
const campaignId = $('Extract Error Info').item.json.campaignId;
const originalError = $('Extract Error Info').item.json.errorMessage;
const dbError = $json.error || 'Unknown DB error';

console.error('[CRITICAL] Failed to mark campaign as FAILED in database!');
console.error(`Campaign ID: ${campaignId}`);
console.error(`Original Error: ${originalError}`);
console.error(`DB Error: ${dbError}`);
console.error('MANUAL INTERVENTION REQUIRED: Update campaign status manually');

return [$json];

// No campaign ID found - log for investigation
const workflowName = $json.workflowName;
const executionId = $json.executionId;
const errorNode = $json.errorNode;
const errorMessage = $json.errorMessage;

console.warn('[WARNING] Error in workflow but no campaign ID found');
console.warn(`Workflow: ${workflowName}`);
console.warn(`Execution ID: ${executionId}`);
console.warn(`Failed Node: ${errorNode}`);
console.warn(`Error: ${errorMessage}`);
console.warn('This may be a non-campaign workflow or error occurred before campaign ID was set');

return [$json];

